import { serve } from "https://deno.land/std@0.168.0/http/server.ts";
import { createClient } from "https://esm.sh/@supabase/supabase-js@2";
import { logErrorToDatabase } from "../_shared/logger.ts";
import { checkRateLimit } from "../_shared/rate-limiter.ts";
import { processVoxisInternally } from "./process-statusz-internal.ts";

const corsHeaders = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type",
};

serve(async (req) => {
  if (req.method === "OPTIONS") {
    return new Response(null, { headers: corsHeaders });
  }

  try {
    const supabaseUrl = Deno.env.get('SUPABASE_URL')!;
    const supabaseServiceKey = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!;

    const formData = await req.formData();
    const audio = formData.get("audio") as File;
    const mode = formData.get("mode") as string;
    const timestamp = formData.get("timestamp") as string;
    const filename = formData.get("filename") as string;
    const userId = formData.get("user_id") as string;
    const treatnotePatientId = formData.get("treatnote_patient_id") as string;

    if (!audio || !mode || !treatnotePatientId) {
      return new Response(
        JSON.stringify({ error: "Hiányzó kötelező mezők: hangfájl, mód, vagy beteg azonosító" }),
        { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    const supabaseAdmin = createClient(supabaseUrl, supabaseServiceKey);

    // Fetch user context BEFORE rate limiting (we need the user profile to identify the limit)
    const { data: profile, error: profileError } = await supabaseAdmin
      .from('profiles')
      .select('company_id, current_telephely_id, full_name, is_solo')
      .eq('user_id', userId)
      .single();

    if (profileError || !profile) {
      console.error("Profile not found:", profileError);
      return new Response(
        JSON.stringify({ error: "Felhasználói profil nem található." }),
        { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    const companyId = profile.company_id;
    const telephelyId = profile.current_telephely_id;

    // ── Rate Limiting ─────────────────────────────────────────────────────
    // 30 requests per 15 minutes limit per user
    const rateLimit = await checkRateLimit(supabaseAdmin, userId, 'native-voice-webhook', 30, 15);

    if (!rateLimit.allowed) {
      await logErrorToDatabase(supabaseAdmin, {
          script_name: 'native-voice-webhook',
          summary: 'Rate limit átlépve',
          full_log: `Túl sok kérés a webhookra. Engedélyezve: 30 / 15 perc.`,
          user_id: userId,
          company_id: companyId,
          telephely_id: telephelyId,
          severity: 'warning'
      });
      return new Response(
          JSON.stringify({ error: "Túl sok hangfelvétel kérés indult ebből a fiókból. Kérjük, várjon perceket, majd próbálja újra." }),
          { status: 429, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    // Clean up stale jobs (processing for more than 10 minutes)
    const tenMinutesAgo = new Date(Date.now() - 10 * 60 * 1000).toISOString();

    const { data: staleJobs } = await supabaseAdmin
      .from('native_voice_jobs')
      .delete()
      .eq('status', 'processing')
      .lt('created_at', tenMinutesAgo)
      .select('id');

    if (staleJobs && staleJobs.length > 0) {
      console.log(`Cleaned up ${staleJobs.length} stale native jobs`);
    }

    // Check if user already has a processing job (that's not stale)
    if (userId) {
      const { data: activeJob } = await supabaseAdmin
        .from('native_voice_jobs')
        .select('id')
        .eq('user_id', userId)
        .eq('status', 'processing')
        .maybeSingle();

      if (activeJob) {
        return new Response(
          JSON.stringify({
            error: "Már fut egy feldolgozás. Kérjük, várjon amíg befejeződik.",
            active_job_id: activeJob.id
          }),
          { status: 409, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }
    }    const finalFilename = filename || audio.name;
    const estimatedDuration = Math.round(audio.size / 16000);

    // Create job record
    const { data: jobData, error: jobError } = await supabaseAdmin
      .from('native_voice_jobs')
      .insert({
        user_id: userId,
        company_id: companyId || null,
        telephely_id: telephelyId || null,
        mode,
        treatnote_patient_id: treatnotePatientId,
        status: 'processing',
        audio_filename: finalFilename,
        duration_seconds: estimatedDuration,
      })
      .select('id')
      .single();

    if (jobError || !jobData) {
      console.error("Failed to create native job:", jobError);
      await logErrorToDatabase(supabaseAdmin, {
        script_name: 'native-voice-webhook',
        summary: 'Feldolgozási sor (job) létrehozása sikertelen',
        full_log: jobError || 'Nincs hibaüzenet',
        user_id: userId,
        company_id: companyId,
        telephely_id: telephelyId
      });
      return new Response(
        JSON.stringify({ error: "Belső hiba: nem sikerült a feldolgozási sort létrehozni. Kérjük, próbálja újra." }),
        { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    const jobId = jobData.id;
    console.log(`Created native job ${jobId} for mode: ${mode}, user: ${userId}`);

    // Since this is NATIVE, we natively call processVoxisInternally and bypass n8n webhooks.
    const openaiApiKey = Deno.env.get("OPENAI_API_KEY");
    const elevenlabsApiKey = Deno.env.get("ELEVENLABS_API_KEY");
    const anthropicApiKey = Deno.env.get("ANTHROPIC_API_KEY");

    let backgroundProcessing = processVoxisInternally(jobId, audio, supabaseAdmin, {
      openai: openaiApiKey || "",
      elevenlabs: elevenlabsApiKey || "",
      anthropic: anthropicApiKey || ""
    }, {
      userId,
      companyId,
      telephelyId,
      logErrorToDatabase
    });

    // Use EdgeRuntime.waitUntil to process in background
    // @ts-ignore
    if (typeof EdgeRuntime !== 'undefined' && EdgeRuntime.waitUntil) {
      // @ts-ignore
      EdgeRuntime.waitUntil(backgroundProcessing);
    } else {
      await backgroundProcessing;
    }

    // Return immediately to frontend
    return new Response(
      JSON.stringify({
        success: true,
        job_id: jobId,
      }),
      { headers: { ...corsHeaders, "Content-Type": "application/json" } }
    );
  } catch (error) {
    console.error("Error in native-voice-webhook function:", error);
    return new Response(
      JSON.stringify({ error: error instanceof Error ? error.message : "Ismeretlen hiba történt a hangfelvétel feldolgozásakor." }),
      { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
    );
  }
});

export async function logErrorToDatabase(
  supabaseAdmin: any,
  params: {
    script_name: string;
    summary: string;
    full_log: string | Error;
    domain?: string;
    severity?: 'info' | 'warning' | 'error';
    metadata?: any;
    user_id?: string | null;
    username?: string | null;
    company_id?: string | null;
    company_name?: string | null;
    telephely_id?: string | null;
    telephely_name?: string | null;
    screenshot_urls?: string[];
  }
) {
  try {
    let fullLogStr = '';
    if (params.full_log instanceof Error) {
      fullLogStr = params.full_log.stack || params.full_log.message;
    } else {
      fullLogStr = String(params.full_log);
    }

    const { error } = await supabaseAdmin.from('error_logs').insert({
      script_name: params.script_name,
      summary: params.summary,
      full_log: fullLogStr,
      domain: params.domain || null,
      severity: params.severity || 'error',
      metadata: params.metadata || {},
      user_id: params.user_id || null,
      username: params.username || null,
      company_id: params.company_id || null,
      company_name: params.company_name || null,
      telephely_id: params.telephely_id || null,
      telephely_name: params.telephely_name || null,
      screenshot_urls: params.screenshot_urls || []
    });

    if (error) {
      console.error('[Logger] Failed to insert error log:', error);
    }
  } catch (err) {
    console.error('[Logger] Unexpected error during logErrorToDatabase:', err);
  }
}

import { logErrorToDatabase } from "./logger.ts";

export async function checkRateLimit(
  supabaseAdmin: any,
  identifier: string,
  endpoint: string,
  maxRequests: number = 10,
  windowMinutes: number = 15
): Promise<{ allowed: boolean; remaining: number; resetTime: Date }> {
  try {
    const windowStart = new Date(Date.now() - windowMinutes * 60 * 1000).toISOString();

    let { data: currentLimit } = await supabaseAdmin
      .from('rate_limits')
      .select('*')
      .eq('identifier', identifier)
      .eq('endpoint', endpoint)
      .maybeSingle();

    if (currentLimit && new Date(currentLimit.first_request_time) < new Date(windowStart)) {
      // Expired, reset it
      const { data: updated } = await supabaseAdmin
        .from('rate_limits')
        .update({ request_count: 1, first_request_time: new Date().toISOString() })
        .eq('id', currentLimit.id)
        .select('*')
        .single();
      currentLimit = updated;
    } else if (!currentLimit) {
      // Doesn't exist, insert
      const { data: inserted, error: insertError } = await supabaseAdmin
        .from('rate_limits')
        .insert({ identifier, endpoint, request_count: 1 })
        .select('*')
        .maybeSingle();

      if (insertError) {
         // Concurrency issue (another request inserted it). Fetch again or fall open.
         return { allowed: true, remaining: maxRequests - 1, resetTime: new Date(Date.now() + windowMinutes * 60 * 1000) };
      }
      currentLimit = inserted;
    } else {
        // Exists and is within valid window
        if (currentLimit.request_count >= maxRequests) {
            const resetTime = new Date(new Date(currentLimit.first_request_time).getTime() + windowMinutes * 60 * 1000);
            return { allowed: false, remaining: 0, resetTime };
        }
        await supabaseAdmin
            .from('rate_limits')
            .update({ request_count: currentLimit.request_count + 1 })
            .eq('id', currentLimit.id);
        currentLimit.request_count += 1;
    }

    if (!currentLimit) {
        return { allowed: true, remaining: maxRequests, resetTime: new Date(Date.now() + windowMinutes * 60 * 1000) };
    }

    const resetTime = new Date(new Date(currentLimit.first_request_time).getTime() + windowMinutes * 60 * 1000);
    return { allowed: true, remaining: maxRequests - currentLimit.request_count, resetTime };
  } catch (error) {
    console.error(`Rate limiter check failed for ${endpoint}:`, error);
    await logErrorToDatabase(supabaseAdmin, {
      script_name: endpoint,
      summary: 'Rate limiter hiba',
      full_log: error instanceof Error ? error.stack || error.message : String(error),
      severity: 'warning'
    });
    // Fall open on db error to not block legitimate traffic
    return { allowed: true, remaining: maxRequests, resetTime: new Date(Date.now() + windowMinutes * 60 * 1000) };
  }
}
